// 01_hello
// Concepts: minimal program, fx block, ret in Void main
// expect: Hello from Aether

fn main() -> Void {
    fx {
        println("Hello from Aether");
    }
    ret;
}

// 02_arithmetic
// Concepts: Int arithmetic, variadic println (never '+' for mixed types)
// expect: sum = 10
// expect: difference = 4
// expect: product = 21
// note: Int / Int is integer-style here
// expect: quotient = 2

fn main() -> Void {
    let a: Int = 7;
    let b: Int = 3;
    let sum: Int = a + b;
    let difference: Int = a - b;
    let product: Int = a * b;
    let quotient: Int = a / b;
    fx {
        println("sum = ", sum);
        println("difference = ", difference);
        println("product = ", product);
        println("quotient = ", quotient);
    }
    ret;
}

// 03_const_let
// Concepts: const declaration, plain let mutability (never `let mut`)
// expect: count = 3 of 3

const Limit: Int = 3;

fn main() -> Void {
    let count: Int = 0;
    loop count < Limit {
        count = count + 1;
    }
    fx {
        println("count = ", count, " of ", Limit);
    }
    ret;
}

// 04_classify
// Concepts: @pure helper, canonical multi-branch via sequential if + ret
// expect: 95 -> ready
// expect: 72 -> review
// expect: 40 -> blocked

@pure
fn classify(score: Int) -> Text {
    if score >= 90 {
        ret "ready";
    }
    if score >= 70 {
        ret "review";
    }
    ret "blocked";
}

fn main() -> Void {
    let a: Text = classify(95);
    let b: Text = classify(72);
    let c: Text = classify(40);
    fx {
        println("95 -> ", a);
        println("72 -> ", b);
        println("40 -> ", c);
    }
    ret;
}

// 05_inline_conditional
// Concepts: inline conditional expression (RHS only), bound before printing
// expect: score is high

fn main() -> Void {
    let score: Int = 14;
    let label: Text = if score > 10 { "high" } else { "low" };
    fx {
        println("score is ", label);
    }
    ret;
}

// 06_countdown
// Concepts: condition loop, fx inside loop body
// expect: 3
// expect: 2
// expect: 1
// expect: liftoff

fn main() -> Void {
    let n: Int = 3;
    loop n > 0 {
        fx {
            println(n);
        }
        n = n - 1;
    }
    fx {
        println("liftoff");
    }
    ret;
}

// 07_range_sum
// Concepts: loop i in 0..n (half-open), accumulator pattern
// expect: sum of 0..5 = 10

fn main() -> Void {
    let sum: Int = 0;
    loop i in 0..5 {
        sum = sum + i;
    }
    fx {
        println("sum of 0..5 = ", sum);
    }
    ret;
}

// 08_break
// Concepts: loop { } with break, guard via plain if (no else needed)
// expect: smallest n with n*n > 200 is 15

fn main() -> Void {
    let n: Int = 1;
    loop {
        if n * n > 200 {
            break;
        }
        n = n + 1;
    }
    fx {
        println("smallest n with n*n > 200 is ", n);
    }
    ret;
}

// 09_clamp_contract
// Concepts: @pre and @post directly above the function, @post uses result
// expect: clamp(150) = 100
// expect: clamp(42) = 42

@pre score >= 0
@post result <= 100
fn clamp(score: Int) -> Int {
    if score > 100 {
        ret 100;
    }
    ret score;
}

fn main() -> Void {
    let high: Int = clamp(150);
    let mid: Int = clamp(42);
    fx {
        println("clamp(150) = ", high);
        println("clamp(42) = ", mid);
    }
    ret;
}

// 100_method_field_shadow
// Concepts: method-local shadowing of a field name, explicit self.field update,
// statement-level else
// expect: valid = 1
// expect: invalid = 1

type Totals {
    valid: Int;
    invalid: Int;

    fn record(score: Int) -> Void {
        let valid: Bool = score >= 70;
        if valid {
            self.valid = self.valid + 1;
        } else {
            self.invalid = self.invalid + 1;
        }
        ret;
    }
}

fn main() -> Void {
    let totals: Totals = new Totals();
    totals.record(90);
    totals.record(10);

    fx {
        println("valid = ", totals.valid);
        println("invalid = ", totals.invalid);
    }
    ret;
}

// 101_method_explicit_context
// Concepts: methods do not capture outer loop locals, caller passes row index
// explicitly
// expect: row 0 -> Alpha
// expect: row 1 -> Beta

type Reporter {
    fn emit(rowIndex: Int, name: Text) -> Void {
        fx {
            println("row ", rowIndex, " -> ", name);
        }
        ret;
    }
}

fn main() -> Void {
    let names: Text[] = ["Alpha", "Beta"];
    let reporter: Reporter = new Reporter();

    loop i in 0..length(names) {
        reporter.emit(i, names[i]);
    }
    ret;
}

// 102_toon_doc_root_bridge
// Concepts: ToonDoc -> toon_root -> ToonNode, object root scalar extraction
// expect: name = Aether
// expect: enabled = true
// expect: count = 2

fn main() -> Void {
