// 103_toon_object_array_extraction
// Concepts: object root, named array extraction, guarded intermediate object,
// _or only on final lookup
// expect: row 0 = A1
// expect: row 1 = EMPTY
// expect: row 2 = B7
// expect: missing = 1

fn main() -> Void {
    if !has_toon() {
        fx { println("yyjson unavailable"); }
        ret;
    }

    let doc: ToonDoc = toon_parse("{\"rows\":[{\"meta\":{\"code\":\"A1\"}},{\"meta\":{}},{\"meta\":{\"code\":\"B7\"}}]}");
    let root: ToonNode = toon_root(doc);
    let rows: ToonNode = toon_key(root, "rows");
    let missing: Int = 0;

    loop i in 0..toon_len(rows) {
        let row: ToonNode = toon_at(rows, i);
        let code: Text = "EMPTY";
        if toon_has_key(row, "meta") {
            let meta: ToonNode = toon_key(row, "meta");
            code = toon_get_text_or(meta, "code", "EMPTY");
        }
        if code == "EMPTY" {
            missing = missing + 1;
        }
        fx {
            println("row ", i, " = ", code);
        }
    }

    fx {
        println("missing = ", missing);
    }

    toon_close(doc);
    ret;
}

// 104_builtin_info_sleep
// Concepts: builtin_info metadata query, TOON inspection of builtin descriptors
// expect: builtin = sleep
// expect: kind = procedure
// expect: backend = delay
// expect: return = Void
// expect: effectful = true

fn describeBuiltin(name: Text) -> Void {
    if !has_toon() {
        fx { println("yyjson unavailable"); }
        ret;
    }

    let metaJson: Text = builtin_info(name);
    let doc: ToonDoc = toon_parse(metaJson);
    let root: ToonNode = toon_root(doc);
    let kind: Text = toon_get_text(root, "kind");
    let backend: Text = toon_get_text(root, "backend_name");
    let returnType: Text = toon_get_text(root, "return_type");
    let effectful: Bool = toon_get_bool_or(root, "effectful", false);

    fx {
        println("builtin = ", name);
        println("kind = ", kind);
        println("backend = ", backend);
        println("return = ", returnType);
        println("effectful = ", effectful);
    }

    toon_close(doc);
    ret;
}

fn main() -> Void {
    describeBuiltin("sleep");
    ret;
}

