// 112_weather_station_report
// Concepts: object-root TOON extraction, pure threshold classify, custom mutable
// totals type with method, missing-field fallbacks, real average formatting,
// per-row and summary output
// expect: station 0: NORTH / 18 / normal
// expect: station 1: EAST / 30 / warn
// expect: station 2: SOUTH / 37 / alert
// expect: station 3: WEST / -5 / alert
// expect: station 4: RIDGE / 0 / normal
// expect: normal = 2
// expect: warn = 1
// expect: alert = 2
// expect: average = 16.00

@pure
fn classifyReading(tempC: Int) -> Text {
    if tempC >= 35 {
        ret "alert";
    }
    if tempC < 0 {
        ret "alert";
    }
    if tempC >= 28 {
        ret "warn";
    }
    ret "normal";
}

type Telemetry {
    count: Int;
    sumTemp: Int;
    normal: Int;
    warn: Int;
    alert: Int;

    fn record(status: Text, tempC: Int) -> Void {
        self.count = self.count + 1;
        self.sumTemp = self.sumTemp + tempC;
        if status == "normal" {
            self.normal = self.normal + 1;
            ret;
        }
        if status == "warn" {
            self.warn = self.warn + 1;
            ret;
        }
        self.alert = self.alert + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("telemetry112.json");
    }
    let root: ToonNode = toon_root(doc);
    let stations: ToonNode = toon_key(root, "stations");
    let totals: Telemetry = new Telemetry();

    loop i in 0..toon_len(stations) {
        let station: ToonNode = toon_at(stations, i);
        let name: Text = toon_get_text_or(station, "name", "UNKNOWN");
        let tempC: Int = toon_get_int_or(station, "tempC", 0);
        let status: Text = classifyReading(tempC);

        totals.record(status, tempC);

        fx {
            println("station ", i, ": ", name, " / ", tempC, " / ", status);
        }
    }

    let average: Real = 0.0;
    if totals.count > 0 {
        average = totals.sumTemp * 1.0 / totals.count;
    }

    fx {
        println("normal = ", totals.normal);
        println("warn = ", totals.warn);
        println("alert = ", totals.alert);
        println("average = ", average:0:2);
    }

    toon_close(doc);
    ret;
}

// 113_library_loan_audit
// Concepts: object-root TOON extraction, pure overdue/fee helpers, const policy,
// custom mutable catalog type with a method that reuses a field name as a local,
// missing-field fallbacks, per-loan and summary output
// expect: loan 0: B101 / alice / overdue / fee 12
// expect: loan 1: B102 / bob / on-time / fee 0
// expect: loan 2: B103 / cara / overdue / fee 32
// expect: loan 3: UNKNOWN / UNKNOWN / on-time / fee 0
// expect: total = 4
// expect: overdue = 2
// expect: on-time = 2
// expect: fees = 44

const GraceDays: Int = 14;
const DailyFine: Int = 2;

@pure
fn isOverdue(daysOut: Int) -> Bool {
    if daysOut > GraceDays {
        ret true;
    }
    ret false;
}

@pure
fn lateFee(daysOut: Int) -> Int {
    if daysOut <= GraceDays {
        ret 0;
    }
    ret (daysOut - GraceDays) * DailyFine;
}

@pure
fn statusLabel(overdue: Bool) -> Text {
    if overdue {
        ret "overdue";
    }
    ret "on-time";
}

type Catalog {
    total: Int;
    overdue: Int;
    onTime: Int;
    fees: Int;

    fn record(overdue: Bool, fee: Int) -> Void {
        self.total = self.total + 1;
        self.fees = self.fees + fee;
        if overdue {
            self.overdue = self.overdue + 1;
            ret;
        }
        self.onTime = self.onTime + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("loans113.json");
    }
    let root: ToonNode = toon_root(doc);
    let loans: ToonNode = toon_key(root, "loans");
    let catalog: Catalog = new Catalog();

    loop i in 0..toon_len(loans) {
        let loan: ToonNode = toon_at(loans, i);
        let id: Text = toon_get_text_or(loan, "id", "UNKNOWN");
        let borrower: Text = toon_get_text_or(loan, "borrower", "UNKNOWN");
        let daysOut: Int = toon_get_int_or(loan, "daysOut", 0);
        let overdue: Bool = isOverdue(daysOut);
        let fee: Int = lateFee(daysOut);

        catalog.record(overdue, fee);

        fx {
            println("loan ", i, ": ", id, " / ", borrower, " / ", statusLabel(overdue), " / fee ", fee);
        }
    }

    fx {
        println("total = ", catalog.total);
        println("overdue = ", catalog.overdue);
        println("on-time = ", catalog.onTime);
        println("fees = ", catalog.fees);
    }

    toon_close(doc);
    ret;
}

// 114_gradebook_rollup
// Concepts: object-root TOON extraction, pure clamp + tiered classify helpers,
// custom mutable gradebook type, clamped real average with fixed precision,
// per-student and summary output
// expect: student 0: Ana / 92 / distinction
// expect: student 1: Ben / 78 / merit
// expect: student 2: Cy / 55 / pass
// expect: student 3: Dee / 100 / distinction
// expect: student 4: Eli / 0 / fail
// expect: distinction = 2
// expect: merit = 1
// expect: pass = 1
// expect: fail = 1
// expect: average = 65.00

const MaxScore: Int = 100;

@pure
fn clampScore(raw: Int) -> Int {
    if raw < 0 {
        ret 0;
    }
    if raw > MaxScore {
        ret MaxScore;
    }
    ret raw;
}

@pure
fn classifyGrade(score: Int) -> Text {
    if score >= 85 {
        ret "distinction";
    }
    if score >= 70 {
        ret "merit";
    }
    if score >= 50 {
        ret "pass";
    }
    ret "fail";
}

type Gradebook {
    count: Int;
    total: Int;
    distinction: Int;
    merit: Int;
    passed: Int;
    failed: Int;

    fn record(grade: Text, score: Int) -> Void {
        self.count = self.count + 1;
        self.total = self.total + score;
        if grade == "distinction" {
            self.distinction = self.distinction + 1;
            ret;
        }
        if grade == "merit" {
            self.merit = self.merit + 1;
            ret;
        }
        if grade == "pass" {
            self.passed = self.passed + 1;
            ret;
        }
        self.failed = self.failed + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("grades114.json");
    }
    let root: ToonNode = toon_root(doc);
    let students: ToonNode = toon_key(root, "students");
    let book: Gradebook = new Gradebook();

    loop i in 0..toon_len(students) {
        let student: ToonNode = toon_at(students, i);
        let name: Text = toon_get_text_or(student, "name", "UNKNOWN");
        let raw: Int = toon_get_int_or(student, "raw", 0);
        let score: Int = clampScore(raw);
        let grade: Text = classifyGrade(score);

        book.record(grade, score);

        fx {
            println("student ", i, ": ", name, " / ", score, " / ", grade);
        }
    }

    let average: Real = 0.0;
    if book.count > 0 {
        average = book.total * 1.0 / book.count;
    }

    fx {
        println("distinction = ", book.distinction);
        println("merit = ", book.merit);
        println("pass = ", book.passed);
        println("fail = ", book.failed);
        println("average = ", average:0:2);
    }

    toon_close(doc);
    ret;
}

// 115_incident_severity_digest
// Concepts: object-root array, GUARDED nested-object extraction (toon_has_key
// before toon_key, then a guarded inner key), fallback codes, coded/missing
// tally via a custom type, per-row and summary output
// expect: incident 0: INC1 / SEV1
// expect: incident 1: INC2 / NONE
// expect: incident 2: INC3 / NONE
// expect: incident 3: UNKNOWN / NONE
// expect: coded = 1
// expect: missing = 3

type Digest {
    coded: Int;
    missing: Int;

    fn record(hasCode: Bool) -> Void {
        if hasCode {
            self.coded = self.coded + 1;
            ret;
        }
        self.missing = self.missing + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

