    }
    let root: ToonNode = toon_root(doc);
    let service: ToonNode = toon_key(root, "service");
    let resources: ToonNode = toon_key(root, "resources");
    let rollout: ToonNode = toon_key(root, "rollout");

    let name: Text = toon_get_text_or(service, "name", "");
    let port: Int = toon_get_int_or(service, "port", 0);
    let replicas: Int = toon_get_int_or(service, "replicas", 0);
    let cpu: Int = toon_get_int_or(resources, "cpu", 0);
    let memoryMb: Int = toon_get_int_or(resources, "memoryMb", 0);
    let strategy: Text = toon_get_text_or(rollout, "strategy", "");
    let maxUnavailable: Int = toon_get_int_or(rollout, "maxUnavailable", 0);

    let report: Report = new Report();

    if !validName(name) {
        report.flag();
        fx {
            println("ISSUE: service name is empty or too long");
        }
    }
    if !validPort(port) {
        report.flag();
        fx {
            print("ISSUE: port out of range (");
            print(port);
            println(")");
        }
    }
    if !atLeast(replicas, 1) {
        report.flag();
        fx {
            println("ISSUE: replicas must be at least 1");
        }
    }
    if !atLeast(cpu, 1) {
        report.flag();
        fx {
            println("ISSUE: cpu must be at least 1");
        }
    }
    if !atLeast(memoryMb, 128) {
        report.flag();
        fx {
            print("ISSUE: memory below minimum (");
            print(memoryMb);
            println(")");
        }
    }
    if !validStrategy(strategy) {
        report.flag();
        fx {
            print("ISSUE: unknown rollout strategy (");
            print(strategy);
            println(")");
        }
    }
    if maxUnavailable > replicas {
        report.flag();
        fx {
            println("ISSUE: maxUnavailable exceeds replicas");
        }
    }

    fx {
        println("issue count: ", report.issues);
    }

    if report.issues > 0 {
        fx {
            println("DEPLOY BLOCKED: ", report.issues, " issue(s)");
        }
        toon_close(doc);
        ret;
    }

    fx {
        println("DEPLOY READY");
    }

    toon_close(doc);
    ret;
}

// 132_grant_application_audit
// Concepts: object-root TOON, const cap, cross-field decision (cap + score),
// derived award amount, custom audit type with multiple counters + running total
// expect: app 0: G1 / approved / 20000
// expect: app 1: G2 / rejected / 0
// expect: app 2: G3 / review / 7500
// expect: app 3: G4 / rejected / 0
// expect: app 4: UNKNOWN / rejected / 0
// expect: approved = 1
// expect: review = 1
// expect: rejected = 3
// expect: total awarded = 27500

const MaxGrant: Int = 50000;

@pure
fn withinCap(requested: Int) -> Bool {
    if requested > MaxGrant {
        ret false;
    }
    ret true;
}

@pure
fn decide(score: Int, ok: Bool) -> Text {
    if !ok {
        ret "rejected";
    }
    if score >= 80 {
        ret "approved";
    }
    if score >= 50 {
        ret "review";
    }
    ret "rejected";
}

@pure
fn award(status: Text, requested: Int) -> Int {
    if status == "approved" {
        ret requested;
    }
    if status == "review" {
        ret requested / 2;
    }
    ret 0;
}

type AuditBook {
    approved: Int;
    review: Int;
    rejected: Int;
    totalAwarded: Int;

    fn record(status: Text, amount: Int) -> Void {
        self.totalAwarded = self.totalAwarded + amount;
        if status == "approved" {
            self.approved = self.approved + 1;
            ret;
        }
        if status == "review" {
            self.review = self.review + 1;
            ret;
        }
        self.rejected = self.rejected + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("grants132.json");
    }
    let root: ToonNode = toon_root(doc);
    let apps: ToonNode = toon_key(root, "applications");
    let book: AuditBook = new AuditBook();

    loop i in 0..toon_len(apps) {
        let app: ToonNode = toon_at(apps, i);
        let id: Text = toon_get_text_or(app, "id", "UNKNOWN");
        let requested: Int = toon_get_int_or(app, "requested", 0);
        let score: Int = toon_get_int_or(app, "score", 0);
        let ok: Bool = withinCap(requested);
        let status: Text = decide(score, ok);
        let amount: Int = award(status, requested);

        book.record(status, amount);

        fx {
            println("app ", i, ": ", id, " / ", status, " / ", amount);
        }
    }

    fx {
        println("approved = ", book.approved);
        println("review = ", book.review);
        println("rejected = ", book.rejected);
        println("total awarded = ", book.totalAwarded);
    }

    toon_close(doc);
    ret;
}

// 133_sprint_board_report
// Concepts: object-root TOON, clamp-normalize, lane classify, blocked flag from
// blockers, custom board type with field reused as a method local (FIELD-001),
// clamped real average with fixed precision
// expect: story 0: S1 / done / false / 95
// expect: story 1: S2 / doing / true / 60
// expect: story 2: S3 / todo / false / 30
// expect: story 3: S4 / done / true / 100
// expect: done = 2
// expect: doing = 1
// expect: todo = 1
// expect: blocked = 2
// expect: average = 71.25

@pure
fn clampProgress(raw: Int) -> Int {
    if raw < 0 {
        ret 0;
    }
    if raw > 100 {
        ret 100;
    }
    ret raw;
}

@pure
fn classifyLane(progress: Int) -> Text {
    if progress >= 90 {
        ret "done";
    }
    if progress >= 50 {
        ret "doing";
    }
    ret "todo";
}

@pure
fn isBlocked(blockers: Int) -> Bool {
    if blockers > 0 {
        ret true;
    }
    ret false;
}

type Board {
    count: Int;
    total: Int;
    done: Int;
    doing: Int;
    todo: Int;
    blocked: Int;

    fn record(lane: Text, blocked: Bool, progress: Int) -> Void {
        self.count = self.count + 1;
        self.total = self.total + progress;
        if blocked {
            self.blocked = self.blocked + 1;
        }
        if lane == "done" {
            self.done = self.done + 1;
            ret;
        }
        if lane == "doing" {
            self.doing = self.doing + 1;
            ret;
        }
        self.todo = self.todo + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("stories133.json");
    }
    let root: ToonNode = toon_root(doc);
    let stories: ToonNode = toon_key(root, "stories");
    let board: Board = new Board();

    loop i in 0..toon_len(stories) {
        let story: ToonNode = toon_at(stories, i);
        let id: Text = toon_get_text_or(story, "id", "UNKNOWN");
        let raw: Int = toon_get_int_or(story, "progress", 0);
        let blockers: Int = toon_get_int_or(story, "blockers", 0);
        let progress: Int = clampProgress(raw);
        let lane: Text = classifyLane(progress);
        let blocked: Bool = isBlocked(blockers);

        board.record(lane, blocked, progress);

        fx {
            println("story ", i, ": ", id, " / ", lane, " / ", blocked, " / ", progress);
        }
    }

    let average: Real = 0.0;
    if board.count > 0 {
        average = board.total * 1.0 / board.count;
    }

    fx {
        println("done = ", board.done);
        println("doing = ", board.doing);
        println("todo = ", board.todo);
        println("blocked = ", board.blocked);
        println("average = ", average:0:2);
    }

    toon_close(doc);
    ret;
}

