// 29_toon_array_root
// Concepts: JSON starting with '[' means root IS the array to iterate
// expect: A: ready
// expect: B: review
// expect: C: blocked

@pure
fn classify(score: Int) -> Text {
    if score >= 90 {
        ret "ready";
    }
    if score >= 70 {
        ret "review";
    }
    ret "blocked";
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc = toon_parse("[{\"name\":\"A\",\"score\":95},{\"name\":\"B\",\"score\":72},{\"name\":\"C\",\"score\":40}]");
    let root: ToonNode = toon_root(doc);

    loop i in 0..toon_len(root) {
        let row: ToonNode = toon_at(root, i);
        let name: Text = toon_get_text(row, "name");
        let score: Int = toon_get_int_or(row, "score", 0);
        let status: Text = classify(score);
        fx {
            println(name, ": ", status);
        }
    }

    toon_close(doc);
    ret;
}

// 301_gradebook_000
// Concepts: parallel Text/Int arrays, flat per-student score blocks, helper functions, indexed accumulation, real average, pass/fail threshold, class rollup
// expect: Pia: avg 63.33 (pass)
// expect: Ivy: avg 68.67 (pass)
// expect: Fay: avg 62.67 (pass)
// expect: Eli: avg 47.00 (fail)
// expect: Mo: avg 69.33 (pass)
// expect: class average: 62.20

fn sumScores(scores: Int[], base: Int, count: Int) -> Int {
    let total: Int = 0;
    loop j in 0..count {
        total = total + scores[base + j];
    }
    ret total;
}

fn grade(total: Int, count: Int) -> Text {
    if total >= 60 * count { ret "pass"; }
    ret "fail";
}

fn main() -> Void {
    let names: Text[] = ["Pia", "Ivy", "Fay", "Eli", "Mo"];
    let scores: Int[] = [59, 53, 78, 79, 89, 38, 61, 36, 91, 59, 43, 39, 63, 96, 49];
    let students: Int = 5;
    let perStudent: Int = 3;
    let classSum: Int = 0;
    loop s in 0..students {
        let base: Int = s * perStudent;
        let total: Int = sumScores(scores, base, perStudent);
        classSum = classSum + total;
        let avg: Real = total * 1.0 / perStudent;
        let status: Text = grade(total, perStudent);
        fx { println(names[s], ": avg ", avg:0:2, " (", status, ")"); }
    }
    let classAvg: Real = classSum * 1.0 / (students * perStudent);
    fx { println("class average: ", classAvg:0:2); }
    ret;
}

