// expect: Rod: 20 x $11.82 = $236.40
// expect: Gear: 14 x $12.83 = $179.62
// expect: Bolt: 27 x $28.82 = $778.14
// expect: Spring: 30 x $10.01 = $300.30
// expect: Plate: 11 x $24.72 = $271.92
// expect: Valve: 37 x $4.70 = $173.90
// expect: Seal: 17 x $6.42 = $109.14
// expect: Nut: 20 x $18.99 = $379.80
// expect: Hinge: 38 x $3.88 = $147.44
// expect: Clamp: 29 x $4.18 = $121.22
// expect: Bracket: 14 x $21.75 = $304.50
// expect: Cable: 13 x $8.57 = $111.41
// expect: grand total: $3113.79
// expect: low-stock items: 0

fn lowFlag(qty: Int, threshold: Int) -> Text {
    if qty < threshold { ret " LOW"; }
    ret "";
}

fn main() -> Void {
    let names: Text[] = ["Rod", "Gear", "Bolt", "Spring", "Plate", "Valve", "Seal", "Nut", "Hinge", "Clamp", "Bracket", "Cable"];
    let qtys: Int[] = [20, 14, 27, 30, 11, 37, 17, 20, 38, 29, 14, 13];
    let prices: Real[] = [11.82, 12.83, 28.82, 10.01, 24.72, 4.70, 6.42, 18.99, 3.88, 4.18, 21.75, 8.57];
    let threshold: Int = 10;
    let n: Int = length(qtys);
    let grand: Real = 0.0;
    let low: Int = 0;
    loop i in 0..n {
        let line: Real = qtys[i] * prices[i];
        grand = grand + line;
        let flag: Text = lowFlag(qtys[i], threshold);
        if qtys[i] < threshold { low = low + 1; }
        fx { println(names[i], ": ", qtys[i], " x $", prices[i]:0:2, " = $", line:0:2, flag); }
    }
    fx { println("grand total: $", grand:0:2); }
    fx { println("low-stock items: ", low); }
    ret;
}

