// 306_recursion_000
// Concepts: classic single-recursion drills (exponentiation, digit reduction, digit count, triangular sum, integer reversal with accumulator), Int %/ division, base cases
// expect: power(4, 3) = 64
// expect: digit_sum(357048) = 27
// expect: count_digits(9695858) = 7
// expect: sum_to(19) = 190
// expect: reverse_int(6939483) = 3849396

fn power(base: Int, exp: Int) -> Int {
    if exp == 0 { ret 1; }
    ret base * power(base, exp - 1);
}

fn digitSum(n: Int) -> Int {
    if n == 0 { ret 0; }
    ret (n % 10) + digitSum(n / 10);
}

fn countDigits(n: Int) -> Int {
    if n < 10 { ret 1; }
    ret 1 + countDigits(n / 10);
}

fn sumTo(n: Int) -> Int {
    if n == 0 { ret 0; }
    ret n + sumTo(n - 1);
}

fn reverseInt(n: Int, acc: Int) -> Int {
    if n == 0 { ret acc; }
    ret reverseInt(n / 10, acc * 10 + n % 10);
}

fn main() -> Void {
    let pw: Int = power(4, 3);
    let ds: Int = digitSum(357048);
    let cd: Int = countDigits(9695858);
    let st: Int = sumTo(19);
    let ri: Int = reverseInt(6939483, 0);
    fx {
        println("power(4, 3) = ", pw);
        println("digit_sum(357048) = ", ds);
        println("count_digits(9695858) = ", cd);
        println("sum_to(19) = ", st);
        println("reverse_int(6939483) = ", ri);
    }
    ret;
}

