// 307_sorting_008
// Concepts: comparison sorting (insertion sort shifts a key left into place; selection sort swaps the running minimum forward), in-place Int[] mutation, indexed element output, min/max of the sorted array
// expect: input: 19 67 17 17 57 53 70 80 74
// expect: algorithm: selection
// expect: sorted[0] = 17
// expect: sorted[1] = 17
// expect: sorted[2] = 19
// expect: sorted[3] = 53
// expect: sorted[4] = 57
// expect: sorted[5] = 67
// expect: sorted[6] = 70
// expect: sorted[7] = 74
// expect: sorted[8] = 80
// expect: min: 17
// expect: max: 80

fn insertionSort(xs: Int[]) -> Int[] {
    let n: Int = length(xs);
    loop i in 1..n {
        let key: Int = xs[i];
        let j: Int = i - 1;
        loop j >= 0 {
            if xs[j] <= key { break; }
            xs[j + 1] = xs[j];
            j = j - 1;
        }
        xs[j + 1] = key;
    }
    ret xs;
}

fn selectionSort(xs: Int[]) -> Int[] {
    let n: Int = length(xs);
    loop i in 0..n {
        let m: Int = i;
        loop j in i + 1..n {
            if xs[j] < xs[m] { m = j; }
        }
        let tmp: Int = xs[i];
        xs[i] = xs[m];
        xs[m] = tmp;
    }
    ret xs;
}

fn joinInts(xs: Int[]) -> Text {
    let out: Text = "";
    let n: Int = length(xs);
    loop i in 0..n {
        if i > 0 { out = out + " "; }
        out = out + int_to_text(xs[i]);
    }
    ret out;
}

