    xs = selectionSort(xs);
    loop i in 0..n {
        fx { println("sorted[", i, "] = ", xs[i]); }
    }
    fx {
        println("min: ", xs[0]);
        println("max: ", xs[n - 1]);
    }
    ret;
}

