// 30_toon_object_with_array
// Concepts: JSON starting with '{' means extract the named array first,
// then iterate the extracted node (never the object root)
// expect: job ingest priority 3
// expect: job retry priority 1

@pure
fn priority(score: Int) -> Int {
    if score >= 90 {
        ret 3;
    }
    if score >= 70 {
        ret 2;
    }
    ret 1;
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc = toon_parse("{\"jobs\":[{\"name\":\"ingest\",\"score\":94},{\"name\":\"retry\",\"score\":35}]}");
    let root: ToonNode = toon_root(doc);
    let jobs: ToonNode = toon_key(root, "jobs");

    loop i in 0..toon_len(jobs) {
        let job: ToonNode = toon_at(jobs, i);
        let name: Text = toon_get_text(job, "name");
        let score: Int = toon_get_int_or(job, "score", 0);
        let level: Int = priority(score);
        fx {
            println("job ", name, " priority ", level);
        }
    }

    toon_close(doc);
    ret;
}

// 310_dp2d_000
// Concepts: 2-D grid dynamic programming flattened into an Int[] addressed r*cols+c — count down/right unique paths, and min-cost down/right path sum; boundary rows/cols, min() via if
// expect: grid: 2x4
// expect: cost: 7 9 9 5 1 5 3 8
// expect: unique_paths = 4
// expect: min_path_sum = 24

fn uniquePaths(rows: Int, cols: Int) -> Int {
    let total: Int = rows * cols;
    let dp: Int[] = [];
    loop i in 0..total {
        dp = dp + [0];
    }
    loop r in 0..rows {
        loop c in 0..cols {
            let idx: Int = r * cols + c;
            if r == 0 { dp[idx] = 1; }
            if c == 0 { dp[idx] = 1; }
            if r > 0 {
                if c > 0 { dp[idx] = dp[(r - 1) * cols + c] + dp[r * cols + (c - 1)]; }
            }
        }
    }
    ret dp[total - 1];
}

fn minPathSum(cost: Int[], rows: Int, cols: Int) -> Int {
    let total: Int = rows * cols;
    let dp: Int[] = [];
    loop i in 0..total {
        dp = dp + [0];
    }
    loop r in 0..rows {
        loop c in 0..cols {
            let idx: Int = r * cols + c;
            if r == 0 {
                if c == 0 { dp[idx] = cost[idx]; }
                if c > 0 { dp[idx] = dp[idx - 1] + cost[idx]; }
            }
            if r > 0 {
                if c == 0 { dp[idx] = dp[(r - 1) * cols + c] + cost[idx]; }
                if c > 0 {
                    let top: Int = dp[(r - 1) * cols + c];
                    let left: Int = dp[r * cols + (c - 1)];
                    let best: Int = top;
                    if left < best { best = left; }
                    dp[idx] = best + cost[idx];
                }
            }
        }
    }
    ret dp[total - 1];
}

fn joinInts(xs: Int[]) -> Text {
    let out: Text = "";
    let n: Int = length(xs);
    loop i in 0..n {
        if i > 0 { out = out + " "; }
        out = out + int_to_text(xs[i]);
    }
    ret out;
}

fn main() -> Void {
    let cost: Int[] = [7, 9, 9, 5, 1, 5, 3, 8];
    let rows: Int = 2;
    let cols: Int = 4;
    let paths: Int = uniquePaths(rows, cols);
    let minsum: Int = minPathSum(cost, rows, cols);
    fx {
        println("grid: ", rows, "x", cols);
        println("cost: ", joinInts(cost));
        println("unique_paths = ", paths);
        println("min_path_sum = ", minsum);
    }
    ret;
}

