        if visited[s] == 0 {
            comps = comps + 1;
            let ignore: Int = dfs(adj, visited, n, s);
        }
    }
    ret comps;
}

fn countEdges(adj: Int[], n: Int) -> Int {
    let total: Int = 0;
    loop u in 0..n {
        loop v in 0..n {
