// 66_agent_report_file
// Concepts: object-root TOON file parsing, custom mutable type, pure helpers,
// score normalization, classification, per-job output, final totals
// expect: job 0: Alpha / ready / 95
// expect: job 1: Beta / review / 78
// expect: job 2: Gamma / blocked / 62
// expect: job 3: Delta / blocked / 41
// expect: job 4: Epsilon / ready / 100
// expect: total = 5
// expect: ready = 2
// expect: review = 1
// expect: blocked = 2

const DefaultScore: Int = 0;

@pure
fn normalizeScore(score: Int) -> Int {
    if score < 0 {
        ret 0;
    }
    if score > 100 {
        ret 100;
    }
    ret score;
}

@pure
fn classifyScore(score: Int) -> Text {
    if score >= 90 {
        ret "ready";
    }
    if score >= 70 {
        ret "review";
    }
    ret "blocked";
}

type Totals {
    total: Int;
    ready: Int;
    review: Int;
    blocked: Int;

    fn record(status: Text) -> Void {
        self.total = self.total + 1;
        if status == "ready" {
            self.ready = self.ready + 1;
            ret;
        }
        if status == "review" {
            self.review = self.review + 1;
            ret;
        }
        self.blocked = self.blocked + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("agent_payload66.json");
    }
    let root: ToonNode = toon_root(doc);
    let jobs: ToonNode = toon_key(root, "jobs");
    let totals: Totals = new Totals();

    loop i in 0..toon_len(jobs) {
        let job: ToonNode = toon_at(jobs, i);
        let name: Text = toon_get_text(job, "name");
        let rawScore: Int = toon_get_int_or(job, "score", DefaultScore);
        let score: Int = normalizeScore(rawScore);
        let status: Text = classifyScore(score);

        totals.record(status);

        fx {
            println("job ", i, ": ", name, " / ", status, " / ", score);
        }
    }

    fx {
        println("total = ", totals.total);
        println("ready = ", totals.ready);
        println("review = ", totals.review);
        println("blocked = ", totals.blocked);
    }

    toon_close(doc);
    ret;
}

// 67_config_validator_nested
// Concepts: nested TOON object extraction, pure validators, issue counting,
// exact issue lines, final validation summary
// expect: ISSUE: port is invalid (0)
// expect: ISSUE: app name is empty or too long
// expect: log severity level: 2
// expect: VALIDATION FAILED: 2 issue(s) found

@pure
fn validPort(port: Int) -> Bool {
    if port < 1 {
        ret false;
    }
    if port > 65535 {
        ret false;
    }
    ret true;
}

@pure
fn validName(name: Text) -> Bool {
    let size: Int = string_len(name);
    if size < 1 {
        ret false;
    }
    if size > 64 {
        ret false;
    }
    ret true;
}

@pure
fn severityForLevel(level: Text) -> Int {
    if level == "critical" {
        ret 4;
    }
    if level == "error" {
        ret 3;
    }
    if level == "warning" {
        ret 2;
    }
    if level == "info" {
        ret 1;
    }
    ret 0;
}

type ValidationSummary {
    issues: Int;

    fn addIssue() -> Void {
        self.issues = self.issues + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc = toon_parse_file("config67.json");
    let root: ToonNode = toon_root(doc);
    let server: ToonNode = toon_key(root, "server");
    let app: ToonNode = toon_key(root, "app");
    let log: ToonNode = toon_key(root, "log");

    let port: Int = toon_get_int_or(server, "port", 0);
    let appName: Text = toon_get_text_or(app, "name", "");
    let logLevel: Text = toon_get_text_or(log, "level", "info");
    let summary: ValidationSummary = new ValidationSummary();

    if !validPort(port) {
        summary.addIssue();
        fx {
            print("ISSUE: port is invalid (");
            print(port);
            println(")");
        }
    }

    if !validName(appName) {
        summary.addIssue();
        fx {
            println("ISSUE: app name is empty or too long");
        }
    }

    fx {
        println("log severity level: ", severityForLevel(logLevel));
    }

    if summary.issues > 0 {
        fx {
            println("VALIDATION FAILED: ", summary.issues, " issue(s) found");
        }
        toon_close(doc);
        ret;
    }

    fx {
        println("CONFIG VALID");
    }

    toon_close(doc);
    ret;
}

