const MaxTxAmount: Int = 10000;

@pure
fn isTxValid(amount: Int) -> Bool {
    if amount < 0 {
        ret false;
    }
    if amount > MaxTxAmount {
        ret false;
    }
    ret true;
}

@pure
fn statusLabel(valid: Bool) -> Text {
    if valid {
        ret "valid";
    }
    ret "invalid";
}

type Ledger {
    batch: Text;
    balance: Int;
    valid: Int;
    invalid: Int;

    fn record(ok: Bool, amount: Int) -> Void {
        if ok {
            self.valid = self.valid + 1;
            self.balance = self.balance + amount;
            ret;
        }
        self.invalid = self.invalid + 1;
        ret;
    }
}

